            ✅ You're on the list! We'll notify you when CCTV goes live.
          </div>
        ) : (
          <div className="cctv-notify-form">
            <div className="section-label" style={{ padding: 0, marginBottom: 8 }}>NOTIFY ME WHEN LIVE</div>
            <input
              className="input-field"
